func formatRate(rate int) string {
	return fmt.Sprintf("%.2f%%", float64(rate)/100)
}

func elementDisplay(mob *domain.Mob) string {
	if mob.ElementLevel > 0 {
		return fmt.Sprintf("%s %d", mob.Element.Display(), mob.ElementLevel)
	}

	return mob.Element.Display()
}

